import { isDate, parse } from 'date-fns';
import moment from 'moment';

import { CustomerTypes } from '@semparar/mf-app-user';
import { AddressData } from '../redux/ducks/addressCard';
import { accountMask, cepMask, getOnlyNumber } from './masks';

const formatTimerNumber = (number: number) => {
  return number > 9 ? `${number}` : `0${number}`;
};

function parseDateString(value: Date, originalValue: string) {
  const parsedDate = isDate(originalValue)
    ? new Date(originalValue)
    : parse(originalValue, 'dd/MM/yyyy', new Date());

  return parsedDate;
}

const formatDate = (date: string) => moment(date).format('YYYY-MM-DD');

const formatDateTime = (date: Date) => moment(date).format('YYYY-MM-DD hh:mm:ss');

const formatPhoneNumber = (number: string) => getOnlyNumber(number);

function capitalizeFirstLetters(str?: string | null) {
  if (str === null || str === undefined) return '';

  const words = str.toLowerCase().split(' ');

  const capitalizedWords = words.map((word) => word.charAt(0).toUpperCase() + word.slice(1));

  const capitalizedString = capitalizedWords.join(' ');

  return capitalizedString;
}

export const removeAccents = (str: string) => {
  return str.normalize('NFD').replace(/[\u0300-\u036f]/g, '');
};

const NAME_REGEXES = {
  validCharacters: /^[\p{L}0-9' .\t\-()]+$/gu,
  invalidCharacters: /[^\p{L}0-9' .\t\-()]/gu,
};

const abbreviateName = (name: string | undefined, limit = 40): string | undefined => {
  if (!name) return name;

  const names = name.split(' ');
  const firstName = names[0];
  const lastName = names.length > 1 ? names[names.length - 1] : '';
  const middleNames = names.slice(1, -1);

  let abbreviatedName = firstName;

  middleNames.forEach((middleName) => {
    if (`${abbreviatedName} ${middleName} ${lastName}`.length > limit) {
      abbreviatedName += ` ${middleName[0]}.`;
    } else {
      abbreviatedName += ` ${middleName}`;
    }
  });

  const finalName = `${abbreviatedName} ${lastName}`.trim();
  const filteredName = finalName.replace(/[^a-zA-Z0-9 \t]/g, '');

  return filteredName.length > limit ? filteredName.slice(0, limit) : filteredName;
};

const formatBankAccount = (agency: string, account: string) =>
  `Ag ${accountMask(agency || '')} | Conta ${accountMask(account || '')}`;

const getMaskedInputDate = (text: string) => {
  if (!text) return text;
  return text
    .replace(/\//g, '')
    .replace(/^(\d{2})(\d)/, '$1/$2')
    .replace(/^(\d{2}\/\d{2})(\d)/, '$1/$2')
    .replace(/^(\d{2}\/\d{2}\/\d{4}).*/, '$1');
};

const getAddressFormat = (
  customerAddress?: (typeof CustomerTypes)['addresses'] | AddressData
) => {
  if (!customerAddress) return '';

  if (customerAddress instanceof Array) {
    const currentUserAddress = customerAddress?.[0];
    if (!currentUserAddress) return '';

    const { streetName, city, state, zipcode, number, neighborhood } = currentUserAddress;

    return `${capitalizeFirstLetters(streetName)}, ${number}\n${capitalizeFirstLetters(
      neighborhood
    )},${capitalizeFirstLetters(city)} - ${state.name}\nCEP ${cepMask(zipcode)}`;
  }

  const { street, number, state, zipCode, city, neighborhood } = customerAddress as AddressData;

  return `${capitalizeFirstLetters(street)}, ${number}\n${capitalizeFirstLetters(
    neighborhood
  )},${capitalizeFirstLetters(city)} - ${state}\nCEP ${cepMask(zipCode)}`;
};

