import { accountReducer, customerReducer, featuresReducer } from '@semparar/mf-app-user';
import { vehiclesReducer } from '@semparar/mf-app-vehicles';

import additionalCardReducer from '../ducks/additionalCard';
import { AddressReducer } from '../ducks/addressCard';
import blockCardReducer from '../ducks/blockCard';
import cardTrackingReducer from '../ducks/cardTracking';
import fintechCashbackReducer from '../ducks/cashback';
import contentsReducer from '../ducks/contents';
import createPasswordReducer from '../ducks/createPassword';
import credencialReducer from '../ducks/credencial';
import cardsReducer from '../ducks/customers/cards';
import productsReducer from '../ducks/customers/products';
import automaticDebtReducer from '../ducks/dacc/automaticDebt';
import partnerBanksReducer from '../ducks/dacc/partnerBanks';
import paymentChangeReducer from '../ducks/dacc/paymentChange';
import downloadInvoiceReducer from '../ducks/downloadInvoice';
import duplicateCardReducer from '../ducks/duplicateCard';
import exampleReducer from '../ducks/example';
import exemptionEligibilityReducer from '../ducks/exemptionEligibility';
import getMarketplaceReducer from '../ducks/getMarketplace';
import homeInvoicesReducer from '../ducks/homeInvoices';
import invoiceFintechReducer from '../ducks/invoice';
import invoicesFintechReducer from '../ducks/invoices';
import invoiceBarcodeReducer from '../ducks/invoices/barcode';
import invoicesListFintechReducer from '../ducks/invoicesList';
import livenessReducer from '../ducks/liveness';
import passwordReducer from '../ducks/password';
import pointsReducer from '../ducks/points';
import activitiesReducer from '../ducks/recentActivities';
import refuelReducer from '../ducks/refuel';
import rescueReducer from '../ducks/rescue';
import searchCepReducer from '../ducks/searchCep';
import simulationReducer from '../ducks/simulation';
import unlockCardReducer from '../ducks/unlockCard';
import updateLimitReducer from '../ducks/updateLimit';
import updatePersonalPasswordReducer from '../ducks/updatePersonalPassword';
import validateCardPasswordReducer from '../ducks/validateCardPassword';
import virtualCardReducer from '../ducks/virtualCard';
import withdrawReducer from '../ducks/withdraw';
import { AppReducers } from './Models';

const fintechCardPlaceReducer: Omit<
  AppReducers,
  'accountReducer' | 'customerReducer' | 'featuresReducer'
> = {
  productsReducer,
  invoicesFintechReducer,
  homeInvoicesReducer,
  invoicesListFintechReducer,
  invoiceFintechReducer,
  unlockCardReducer,
  getMarketplaceReducer,
  validateCardPasswordReducer,
  downloadInvoiceReducer,
  invoiceBarcodeReducer,
  automaticDebtReducer,
  partnerBanksReducer,
  paymentChangeReducer,
  fintechCashbackReducer,
  activitiesReducer,
  virtualCardReducer,
  livenessReducer,
  createPasswordReducer,
  credencialReducer,
  cardsReducer,
  blockCardReducer,
  duplicateCardReducer,
  passwordReducer,
  simulationReducer,
  withdrawReducer,
  AddressReducer,
  searchCepReducer,
  contentsReducer,
  exemptionEligibilityReducer,
  cardTrackingReducer,
  updateLimitReducer,
  additionalCardReducer,
  pointsReducer,
  rescueReducer,
};

export default {
  accountReducer,
  customerReducer,
  featuresReducer,
  exampleReducer,
  refuelReducer,
  updatePersonalPasswordReducer,
  vehiclesReducer,
  ...fintechCardPlaceReducer,
};

