   428→export function groupBy<T, K extends PropertyKey>(
   429→  array: T[],
   430→  iteratee: ((item: T) => K) | keyof T
   431→): Record<K, T[]> {
   432→  return array.reduce((result, item) => {
   433→    const key =
   434→      typeof iteratee === 'function'
   435→        ? (iteratee as (item: T) => K)(item)
   436→        : (item[iteratee] as unknown as K);
   437→
   438→    if (!result[key]) {
   439→      result[key] = [];
   440→    }
   441→
   442→    result[key].push(item);
   443→
   444→    return result;
   445→  }, {} as Record<K, T[]>);
   446→}
