    31→export async function markAsRedeemed(accountId: string): Promise<boolean> {
    32→  const { rewardPermissionActions } = useRootStore.getState();
    33→
    34→  try {
    35→    const document: PermissionDocumentInput = {
    36→      codigoCliente: accountId,
    37→      status: 1,
    38→      value: JSON.stringify({
    39→        invoiceCashbackRedemption: {
    40→          redeemedAtDate: new Date().toISOString(),
    41→        },
    42→      }),
    43→    };
    44→
    45→    const response = await savePermissionApi(document);
    46→
